const rows = items;

let total = 0;
const byCategory = {};
const byImportance = {};

for (const item of rows) {
  const amount = Number(item.json.amount) || 0;
  const category = item.json.category || "unknown";
  const importance = item.json.importance || "unknown";

  total += amount;

  byCategory[category] = (byCategory[category] || 0) + amount;
  byImportance[importance] = (byImportance[importance] || 0) + amount;
}

return [
  {
    json: {
      total,
      byCategory,
      byImportance,
      count: rows.length
    }
  }
];

