const rows = $input.all().map(i => i.json);

const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth(), 1); 

function toDate(x){
  const d = new Date(x);
  return isNaN(d) ? null : d;
}

const filtered = rows.filter(r => {
  const d = toDate(r.date);
  return d && d >= start && d <= now;
});

const sumsByImp = { Luxury:0, Necessary:0, Investment:0, Unknown:0 };
const sumsByCat = {};

let total = 0;
for (const r of filtered) {
  const amt = parseFloat(r.amount ?? 0) || 0;
  const impRaw = (r.importance ?? "Unknown").toString();
  const imp = sumsByImp[impRaw] !== undefined ? impRaw : "Unknown";
  const cat = (r.category ?? "Unspecified").toString();

  total += amt;
  sumsByImp[imp] += amt;
  sumsByCat[cat] = (sumsByCat[cat] || 0) + amt;
}

const topCats = Object.entries(sumsByCat)
  .sort((a,b) => b[1]-a[1])
  .slice(0,5)
  .map(([category, amount]) => ({ category, amount }));

const pct = (x) => total ? Math.round((x/total)*100) : 0;

return [{
  period_start: start.toISOString(),
  period_end: now.toISOString(),
  tx_count: filtered.length,
  total_spend: total,
  by_importance: sumsByImp,
  by_importance_pct: {
    Luxury: pct(sumsByImp.Luxury),
    Necessary: pct(sumsByImp.Necessary),
    Investment: pct(sumsByImp.Investment),
    Unknown: pct(sumsByImp.Unknown),
  },
  top_categories: topCats,
}];

let text = $json.content?.parts?.[0]?.text || "";

// تنظيف أي markdown
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(text);
} catch (e) {
  throw new Error("Invalid JSON from AI: " + text);
}

const type = parsed.type || "Expense";

// بناء الناتج النهائي
const result = {
  type,
  amount: parsed.amount ?? null,
  category: parsed.category ?? null,
  goal_name: type === "Goal" ? (parsed.goal_name || null) : null,
  goal_action: type === "Goal" ? (parsed.goal_action || null) : null,
  importance: type === "Expense" ? (parsed.importance || null) : null,
  date: new Date().toISOString()
};

// حماية إضافية
if (type === "Goal" && !result.goal_name) {
  throw new Error("Goal type requires goal_name from AI");
}

return [
  {
    json: result
  }
];
